fn solve(nums: Vec<i64>) -> bool {
    let n = nums.len();
    if n < 3 {
        return false;
    }
    for p in 1..n - 2 {
        for q in (p + 1)..n - 1 {
            let mut valid = true;
            // Check first part: 0 to p is strictly increasing
            for i in 0..p {
                if nums[i] >= nums[i + 1] {
                    valid = false;
                    break;
                }
            }
            if !valid {
                continue;
            }
            // Check second part: p to q is strictly decreasing
            for i in p..q {
                if nums[i] <= nums[i + 1] {
                    valid = false;
                    break;
                }
            }
            if !valid {
                continue;
            }
            // Check third part: q to end is strictly increasing
            for i in q..n - 1 {
                if nums[i] >= nums[i + 1] {
                    valid = false;
